using System.ComponentModel;
using System.Net;
using System.Text.Json;

namespace ResearchAgent;

/// <summary>
/// Provides web search functionality via the Google Custom Search JSON API.
/// Falls back to a simulated response when API credentials are not configured.
/// </summary>
public static class WebSearchTool
{
    private static readonly HttpClient HttpClient = new();

    public static async Task<string> SearchAsync(
        [Description("The search query to look up on the web")] string query)
    {
        var apiKey = Environment.GetEnvironmentVariable("GOOGLE_SEARCH_API_KEY");
        var searchEngineId = Environment.GetEnvironmentVariable("GOOGLE_SEARCH_ENGINE_ID");

        if (!string.IsNullOrEmpty(apiKey) && !string.IsNullOrEmpty(searchEngineId))
        {
            return await LiveSearchAsync(query, apiKey, searchEngineId);
        }

        Console.WriteLine($"  [WebSearch] \"{query}\" (simulated — set GOOGLE_SEARCH_API_KEY and GOOGLE_SEARCH_ENGINE_ID for live results)");
        return SimulateSearch(query);
    }

    private static async Task<string> LiveSearchAsync(
        string query, string apiKey, string searchEngineId)
    {
        Console.WriteLine($"  [WebSearch] \"{query}\"");

        var encodedQuery = WebUtility.UrlEncode(query);
        var url = $"https://www.googleapis.com/customsearch/v1?key={apiKey}&cx={searchEngineId}&q={encodedQuery}&num=5";

        var response = await HttpClient.GetAsync(url);
        response.EnsureSuccessStatusCode();

        using var doc = JsonDocument.Parse(await response.Content.ReadAsStringAsync());
        var results = new List<string>();

        if (doc.RootElement.TryGetProperty("items", out var items))
        {
            foreach (var item in items.EnumerateArray())
            {
                var title = item.GetProperty("title").GetString();
                var snippet = item.GetProperty("snippet").GetString();
                var link = item.GetProperty("link").GetString();
                results.Add($"- {title}: {snippet} (Source: {link})");
            }
        }

        return results.Count > 0
            ? string.Join("\n", results)
            : "No results found.";
    }

    private static string SimulateSearch(string query)
    {
        var lowerQuery = query.ToLowerInvariant();

        // Provide plausible simulated results based on keywords
        var results = new List<string>
        {
            $"- Overview of {query}: A comprehensive introduction covering the key concepts, history, and current state of {query}. (Source: https://en.wikipedia.org/wiki/{Uri.EscapeDataString(query)})",
            $"- Recent developments in {query}: Researchers have made significant progress in this area, with new findings published in 2025 highlighting breakthroughs and emerging trends. (Source: https://www.nature.com/articles/{query.Replace(' ', '-').ToLowerInvariant()})",
            $"- {query} practical applications: Industry experts discuss real-world uses spanning healthcare, technology, and education sectors. (Source: https://www.sciencedaily.com/releases/2025/{query.Replace(' ', '_').ToLowerInvariant()}.htm)",
            $"- Expert analysis of {query}: Leading researchers provide in-depth analysis of challenges, opportunities, and future directions in this field. (Source: https://arxiv.org/abs/2025.{Math.Abs(query.GetHashCode()) % 10000:D5})",
            $"- {query} — a beginner's guide: Step-by-step introduction for newcomers covering foundational principles and key terminology. (Source: https://www.britannica.com/topic/{Uri.EscapeDataString(query)})",
        };

        return string.Join("\n", results);
    }
}

namespace ResearchAgent;

/// <summary>
/// In-memory note storage used by the research agent to record findings.
/// </summary>
public sealed class NoteTakingService
{
    private readonly List<(string Title, string Content)> _notes = [];

    public void AddNote(string title, string content)
    {
        _notes.Add((title, content));
        Console.WriteLine($"  [NoteTaking] Saved: \"{title}\"");
    }

    public IReadOnlyList<string> GetAllNotes()
    {
        return _notes
            .Select((n, i) => $"[{i + 1}] {n.Title}\n{n.Content}")
            .ToList();
    }
}

