 using System.ComponentModel;
 using Microsoft.Extensions.AI;
 using Microsoft.Extensions.DependencyInjection;
 using Microsoft.Extensions.Logging;
 using Microsoft.Agents.AI;
 using OpenAI;
 using ResearchAgent;

 var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
     ?? throw new InvalidOperationException(
         "Set the OPENAI_API_KEY environment variable before running.");

 const string modelId = "gpt-4o-mini-2024-07-18";

 var services = new ServiceCollection();
 services.AddLogging(b => b.AddConsole().SetMinimumLevel(LogLevel.Warning));
 services.AddSingleton(new NoteTakingService());

 var openAiClient = new OpenAIClient(apiKey);
 IChatClient chatClient = openAiClient.GetChatClient(modelId).AsIChatClient();
 services.AddSingleton(chatClient);

 var sp = services.BuildServiceProvider();

 var noteService = sp.GetRequiredService<NoteTakingService>();
 var loggerFactory = sp.GetRequiredService<ILoggerFactory>();

 var tools = new AITool[]
 {
     AIFunctionFactory.Create(
         WebSearchTool.SearchAsync,
         nameof(WebSearchTool.SearchAsync),
         "Search the web for information on a query. Returns a list of result snippets."),
     AIFunctionFactory.Create(
         ([Description("The title for the note")] string title,
          [Description("The content to save")] string content) =>
         {
             noteService.AddNote(title, content);
             return $"Note saved: {title}";
         },
         "SaveNote",
         "Save a research note with a title and content for later reference."),
     AIFunctionFactory.Create(
         () => noteService.GetAllNotes(),
         "GetNotes",
         "Retrieve all saved research notes."),
 };

 const string instructions = """
     You are a research assistant. When given a topic:
     1. Break the topic into 2-3 key search queries.
     2. Search the web for each query using the SearchAsync tool.
     3. Save important findings as notes using the SaveNote tool.
     4. After researching, retrieve your notes with GetNotes.
     5. Produce a well-structured summary with key findings and sources.
     Be thorough but concise. Always cite sources from your search results.
     """;

 var agent = new ChatClientAgent(
     chatClient,
     instructions: instructions,
     name: "ResearchAgent",
     description: "An AI agent that researches topics by searching the web and taking notes.",
     tools: tools,
     loggerFactory: loggerFactory,
     services: sp);

 Console.WriteLine("=== Research Agent ===");
 Console.Write("Enter a topic to research: ");
 var topic = Console.ReadLine();

 if (string.IsNullOrWhiteSpace(topic))
 {
     Console.WriteLine("No topic provided. Exiting.");
     return;
 }

 Console.WriteLine($"\nResearching: {topic}\n");

 var session = await agent.CreateSessionAsync();

 var response = await agent.RunAsync(
     $"Research the following topic and provide a comprehensive summary: {topic}",
     session,
     options: null);

 Console.WriteLine("=== Research Summary ===\n");
 Console.WriteLine(response.Text);

 Console.WriteLine("\n=== Saved Notes ===\n");
 foreach (var note in noteService.GetAllNotes())
 {
     Console.WriteLine(note);
     Console.WriteLine();
 }

